// 1. Récupération des données et paramètres
const results = $input.first().json.result || [];
const pinned = $input.first().json.Pinned_count || 0;

const tag_count = 200; 
const nb_selection_ia = $input.first().json.Parameters.ai_selection_count; 
const nb_pool = $input.first().json.Parameters.working_pool_count; 
const diversity_limit = $input.first().json.Parameters.concept_diversity_limit

// Paramètres de pondération (Weights) venant de l'UI
const VolumeW = $input.first().json.Parameters.Volume;
const CompetitionW = $input.first().json.Parameters.Competition;
const TransactionW = $input.first().json.Parameters.Transaction;
const NicheW = $input.first().json.Parameters.Niche;
const CPCW = $input.first().json.Parameters.CPC;

const evergreenStabilityRatio = $input.first().json.Parameters.evergreen_stability_ratio;
const evergreenMinVol = $input.first().json.Parameters.evergreen_minimum_volume;
const evergreenAvgVol = $input.first().json.Parameters.evergreen_avg_volume;
const trendingDropThreshold = $input.first().json.Parameters.trending_dropping_threshold;
const trendingCurrentMonthMinVol = $input.first().json.Parameters.trending_current_month_min_volume;
const trendingGrowthFactor =$input.first().json.Parameters.trending_growth_factor;
const promisingMinScore = $input.first().json.Parameters.promising_min_score;
const promisingCompetition = $input.first().json.Parameters.promising_competition;

const is_selection_ia = $input.first().json.is_selection_ai;
const is_current_eval = $input.first().json.is_current_eval;
const is_current_pool = $input.first().json.is_current_pool;



// 2. Configuration du mode (Weights)
const modeParams = { 
    balanced: {
        a: VolumeW, b: CompetitionW, g: TransactionW, d: NicheW, e: CPCW
        //minT: 5, minN: 2
    }
};

// 3. Pré-calcul global pour la normalisation (Basé sur le volume déjà boosté)
const maxVol = Math.max(...results.map(i => i.search_volume || 0), 100); 
const maxRefCPC = 2.5; 

// 4. Fonction de traitement principale
const processKeywordsForMode = (modeName) => {
    const p = modeParams[modeName];

    let processed = results.map(item => {
        // --- ON UTILISE LE VOLUME DIRECTEMENT ---
        const vol = item.search_volume || 0; 

        const rawComp = (item.competition !== null && item.competition !== undefined) ? parseFloat(item.competition) : 0.5;
        const txScore = item.transactional_score || 5;
        const nicheScore = item.niche_score || 5;
        const rawCPC = item.cpc || 0;

        // Hard Filters (Filtres de sécurité)
        if (txScore < p.minT || nicheScore < p.minN) return null;

        // --- NORMALISATION ---
        const V = Math.log(vol + 1) / Math.log(maxVol + 1);
        const C = 1 - rawComp;
        const T = Math.pow(txScore / 10, 2);
        const N = Math.pow(nicheScore / 10, 2);
        const E = Math.min(1, rawCPC / maxRefCPC);

        // --- CALCUL DU SCORE FINAL ---
        let finalScore = 100 * (
            Math.pow(V || 0.01, p.a) * Math.pow(C || 0.01, p.b) * Math.pow(T || 0.01, p.g) * Math.pow(N || 0.01, p.d) * Math.pow(E || 0.01, p.e)
        );

        // Boosts de pertinence
        //if (item.intent_label === 'Title') finalScore *= 1.2;
        const wordCount = (item.keyword || "").split(' ').filter(w => w.length > 0).length;
        if (wordCount >= 3) finalScore *= 1.1;

        // --- TRAITEMENT DE L'HISTORIQUE (ORDRE : RÉCENT -> ANCIEN) ---
        // On ne fait PAS de .reverse(). On travaille sur la donnée brute.
        //let history = item.volume_history || [];
        const history = [...(item.volume_history || [])];
        while (history.length < 12) history.push(0);

        // Mois actuel (Aujourd'hui) = Index 0
        const currentMonth = history[0]; 

        // Moyenne des 3 mois les plus récents (Index 0, 1, 2)
        const recentAvg = (history[0] + history[1] + history[2]) / 3;

        // Moyenne des 9 mois précédents (Index 3 à 11)
        const pastMonths = history.slice(3, 12);
        const historicalAvg = pastMonths.reduce((a, b) => a + b, 0) / (pastMonths.length || 1) || 1;

        // 1. TRENDING (La Croissance Immédiate)
        // Garde la règle du !isCrashing pour éviter de célébrer une chute
        const isDropping = currentMonth < (history[1] * trendingDropThreshold);
        const isTrending = !isDropping && (recentAvg > historicalAvg * trendingGrowthFactor) && currentMonth > trendingCurrentMonthMinVol;
         //const isTrending = (recentAvg > historicalAvg * 1.5) && (currentMonth > historicalAvg * 1.2) && currentMonth > 150;




         // --- EVERGREEN (Stabilité Long Terme) ---
        // 1. Un volume minimum significatif pour mériter le badge
        // 2. Un écart min/max maîtrisé (pas de "montagnes russes")
        // 3. Pas en train de "Trender" (pour isoler la stabilité)

        const minVol = Math.min(...history.filter(v => v > 0));
        const maxVolInHistory = Math.max(...history);
        const stabilityRatio = maxVolInHistory / (minVol || 1);

        const isEvergreen = !isTrending && 
                            vol > evergreenAvgVol && 
                            stabilityRatio < evergreenStabilityRatio && // Le pic n'est pas 4x plus haut que le creux
                            minVol > (vol * evergreenMinVol); // Le pire mois garde au moins 30% du trafic actuel


         // 3. PROMISING (Le Meilleur ROI)
        // On se base sur le score final de 0 à 100 qu'on a calculé
        const isPromising = finalScore > promisingMinScore && rawComp < promisingCompetition;

        return {
            ...item,
            opportunity_score: Math.round(finalScore),
            status: {
                trending: isTrending,
                evergreen: isEvergreen,
                promising: isPromising
            }
        };
    }).filter(i => i !== null);





    // MODIFICATION ICI : Tri à deux niveaux
    // 1. On place les 'is_pinned' en premier
    // 2. On trie ensuite par opportunity_score
    processed.sort((a, b) => {
        if (a.is_pinned && !b.is_pinned) return -1;
        if (!a.is_pinned && b.is_pinned) return 1;
        return b.opportunity_score - a.opportunity_score;
    });


    // 5. Sélection et Diversité (Concept Tracker)
    const selectedTags = [];
    const conceptTracker = {};
    for (const item of processed) {
        if (selectedTags.length >= tag_count) break;
        const concept = item.keyword.toLowerCase().split(' ').slice(0, 2).join(' ');
        conceptTracker[concept] = (conceptTracker[concept] || 0) + 1;

        if (conceptTracker[concept] <= diversity_limit) {
            selectedTags.push(item);
        }
    }

    // 6. Marquage final
    return selectedTags.map((item, index) => {
       // Calcul de l'appartenance au pool IA (Top 13)
      // On vérifie si l'index est < 13 OU si l'item est épinglé
        // (Même si le tri garantit qu'il sera en haut, cette double sécurité est propre)
        const isInTopSelection = (index < nb_selection_ia);
        const isInPool = (index < nb_pool);

        return {
            ...item,
            is_selection_ia: is_selection_ia ?? isInTopSelection,
            is_current_eval: is_current_eval ?? isInTopSelection,
            is_current_pool: is_current_pool ?? isInPool,
            is_pinned: item.is_pinned || false
        };
    });
};

return {
    balanced: processKeywordsForMode('balanced')
};
